import EventEmitter = require('jibo-eventemitter3');
import bt from './bt';

declare namespace flow {
    export enum State {
        IN_PROGRESS, // activity is running, send it updates
        DONE,        // activity is done, collect return values and transition
        READY,       // ready to execute activity
        EXITED,      // fsm has exited, no further stepping allowed.
        PAUSED       // flow is paused, due to hitting an exception or is waiting for asynchronous stopping. Callbacks will set the state to ready, done, or exited as appropirate
    }

    export class FlowExecutor {
        blackboard:any;
        emitter:EventEmitter;
        result:any;
        start():void;
        update():boolean;
        stop():Promise<void>;
        destroy():void;
        stopAndDestroy():Promise<void>;
        state:State;
    }
    
    export class ActivityImplementation {
        name:string;
        class:string;
        assetPack:string;
        options:any;
        result:any;
        optionCodeThis:any;  // All user code supplied in Options has access to a 'this.' which is stored here.
        exceptionPayload:any; // if result starts with a ~, this is (potentially) the payload accompanying it.
        flowExecutor:any;
        transitions:[any];
        exceptions:[any];
    }

    export function register(name:string, namespace:string, classRef:new (options:any)=>ActivityImplementation):void;
    export function create(uri:string|Function, overrides?:any):FlowExecutor;
    export function run(uri:string|Function, overrides?:any, onFinishedCallback?:(err, status:bt.Status)=>void):FlowExecutor;
}

export default flow;